--
-- Triggers `db_store`
--
DELIMITER $$
CREATE TRIGGER `sync_store_to_master` AFTER UPDATE ON `db_store` FOR EACH ROW BEGIN
                        UPDATE `bill_xml`.`db_store` 
                        SET store_name = NEW.store_name, 
                            mobile = NEW.mobile, 
                            email = NEW.email, 
                            address = NEW.address, 
                            city = NEW.city, 
                            state = NEW.state, 
                            country = NEW.country, 
                            status = NEW.status
                        WHERE id = NEW.id;
                    END
$$
DELIMITER ;

